    },
    {
      "title": "OFFSET pagination degrades at depth",
      "description": "OFFSET $3 forces the database to scan and discard `offset` rows before returning results. At page 10000 with pageSize 20, the DB scans 200,000 rows. For high-volume order histories, consider cursor-based pagination (WHERE created_at < $lastSeen) which is O(1) regardless of page depth.",
      "location": "SQL query OFFSET clause"
    }
  ],

